const PRECACHE="precache-v1",RUNTIME="runtime",PRECACHE_URLS=["/upload/index.html","/upload/index.js","/upload/style.min.css","/assets/bootstrap.min.css","/assets/copy.svg","/assets/done.svg","/assets/favicon.svg","/assets/favicon-thin.svg","/upload/manifest.json","/assets/upload-file.svg","/assets/upload-file.png","/assets/Roboto/Roboto-Bold.ttf","/assets/Roboto/Roboto-Regular.ttf"];self.addEventListener("install",s=>{s.waitUntil(caches.open(PRECACHE).then(s=>s.addAll(PRECACHE_URLS)).then(self.skipWaiting()))}),self.addEventListener("activate",s=>{const e=[PRECACHE,RUNTIME];s.waitUntil(caches.keys().then(s=>s.filter(s=>!e.includes(s))).then(s=>Promise.all(s.map(s=>caches.delete(s)))).then(()=>self.clients.claim()))}),self.addEventListener("fetch",s=>{s.request.url.startsWith(self.location.origin)&&s.respondWith(fetch(s.request))});